import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import {Grid } from '@material-ui/core';
import { CartegoryCard } from './CartegoryCard';
import { PrivilegeCard } from './PrivilegeCard';
import { staffConstants, staffStrings } from '../../config';
import { staffActions } from '../../actions';
import { customSuperSetState } from '../../../../../utils';


/**
 * TO DO
 * More nested privileges in details of functions
 * 
 */
const style = theme => ({
    root: {
    },
    catInput : {
        display : "flex",
        flexGrow : 1
    }
})
class _StaffCategories extends Component {
    constructor(props) {
        super(props);
        this.state={
            selectedCat : {},
            categories : []
        }
    }
    updateCategoryPrivilege=name=>privileges=>{
        const {categories} = this.state;
        if(categories) for(const i in categories){
            if(categories.hasOwnProperty(i)){
                const cat = categories[i];
                if(cat.name === name){
                    categories[i].privileges = privileges
                }
            }
        }
        
        this.setState({categories});
    }
    componentDidMount(){
        if(!this.props[staffStrings.categories]){
            staffActions.getStaffCategories(done=>{

            })(this.props.dispatch);
        }
    }
    setSeleetedCat = selectedCat=>()=>this.setState({selectedCat})
    render() {
        const {classes, [staffStrings.categories] : categories =[]} = this.props;
        const {selectedCat} = this.state;
        return (
            <Grid container spacing={8} className={classes.root}>
                <Grid item xs={12} sm={12} md={6} lg={6} xl={6}>
                    <CartegoryCard 
                        categories={categories}
                        setSeleetedCat={this.setSeleetedCat.bind(this)}
                        />                  
                </Grid>
                <Grid item xs={12} sm={12} md={6} lg={6} xl={6}>
                    <PrivilegeCard selectedCat={selectedCat}
                        superSetState={this.updateCategoryPrivilege.bind(this)}/>
                </Grid>
            </Grid>
        );
    }
}


_StaffCategories.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({staffReducer}) => ({
    [staffStrings.categories] : staffReducer[staffStrings.categories]
})


export const StaffCategories = connect(mapStateToProps)(withStyles(style)(_StaffCategories));