import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { ListItem, CardContent, Card, CardHeader, List, Typography, Divider, FormControlLabel, Checkbox } from '@material-ui/core';
import { appActions, alertAction } from '../../../../../actions';

const privileges = [
    {name : "Admin", privileges : [
        {name : "Account", value : 1},
        {name : "Staff", value : 2},
        {name : "Calender", value : 3},
    ]},
    {name : "Teacher", privileges : [
        {name : "Account", value : 4},
        {name : "Staff", value : 5},
        {name : "Calender", value : 6},
    ]},
    {name : "General", privileges : [
        {name : "Account", value : 7},
        {name : "Staff", value : 8},
        {name : "Calender", value : 9},
    ]},
]
const style = theme => ({
    root: {
    }
})
class _PrivilegeCard extends Component {
    
    onCheckChange=(value)=>e=>{
        let {name, privileges} = this.props.selectedCat || {};
        if(!name) appActions.showSnackbar(
            alertAction.error("Select a category first")
        )(this.props.dispatch)
        if(e.target.checked){
            if(privileges) 
                privileges.push(value);
            else privileges = [value];
        }else privileges.splice(privileges.indexOf(value), 1);
        this.props.superSetState(name)(privileges);
    }
    render() {
        const {classes, selectedCat, /* privileges */} = this.props;
        return (
            <Card>
                <CardHeader 
                    title="Privileges"
                    subheader={selectedCat && "Privileges for " +selectedCat.name+ " category"}/>
                    <CardContent>
                        <List>
                        {privileges && privileges.map((priv, index) => 
                            <ListItem key={index} style={{
                                display: "flex", 
                                flexDirection: "column", 
                                alignItems : "flex-start", 
                                padding : 0
                                }} divider key={index}>
                                <Typography style={{fontWeight: "bold"}}>{priv.name}</Typography>
                                <Divider/>
                                {priv.privileges.map((pItem, i)=>{
                                    let isChecked = selectedCat && selectedCat.privileges && selectedCat.privileges.indexOf(pItem.value) != -1 || false; 
                                    return <FormControlLabel
                                        key={i}
                                        control={
                                            <Checkbox
                                                checked={isChecked}
                                                onChange={this.onCheckChange(pItem.value)}
                                                />}
                                        label={pItem.name}/>
                                })}
                            </ListItem>)}
                        </List>
                </CardContent>
            </Card>
        );
    }
}


_PrivilegeCard.propTypes = {
    classes : PropTypes.object.isRequired,
    selectedCat : PropTypes.object,
    privileges : PropTypes.array,
    superSetState : PropTypes.func,
};



export const PrivilegeCard = connect()(withStyles(style)(_PrivilegeCard));