import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    Card, CardHeader, CardContent, CardActionArea, 
    CardActions, List, ListItem, ListItemText, ListItemIcon,
    Button, TextField
} from '@material-ui/core';
import { Delete } from '@material-ui/icons';
import { InfoText } from '../../../../includes';



const style = theme => ({
    root: {
    },
    catInput : {
        display : "flex",
        flexGrow : 1
    }
})
class _CartegoryCard extends Component {
    constructor(props) {
        super(props);
        this.state={
            data : {
                category : ""
            }
        }
        if(props.getContext) props.getContext(this);
    }
    handleOnChange=name=>e=>{
        let data = {...this.state.data};
        data[name] = e.target.value;
        this.setState({data});

        //add to the pool
    }
    render() {
        const {classes, categories, setSeleetedCat} = this.props;
        const category = this.state.data.category
        return (
            <Card>
                <CardHeader 
                    title="Staff Categories"
                    subheader="The different types of staff"/>
                    <CardContent>
                        <List>
                        {categories && categories.map((cat, index) => 
                            <ListItem  onClick={setSeleetedCat(cat)} style={{padding : 0}} divider key={index} button>
                                <ListItemText>
                                    {cat.name}
                                </ListItemText>
                                <ListItemIcon style={{minWidth:0}}>
                                    <Delete/>
                                </ListItemIcon>
                            </ListItem>)}
                        </List>
                </CardContent>
                <CardActions>
                    <div className={classes.catInput}>
                        <TextField
                            style={{width : "100%"}}
                            value={category}
                            variant="standard"
                            placeholder="New Category"
                            onChange={this.handleOnChange("category")}
                            margin="normal"/>
                    </div>
                        <Button variant="outlined">Add</Button>
                </CardActions>
                <CardActionArea>
                    <InfoText>
                        Admin, Teacher and Staff are the default and can't be deleted
                    </InfoText>
                </CardActionArea>
            </Card>  
        );
    }
}


_CartegoryCard.propTypes = {
    classes : PropTypes.object.isRequired,
    categories : PropTypes.array,
    setSeleetedCat : PropTypes.func,    
    getContext : PropTypes.func,
};


export const CartegoryCard = connect()(withStyles(style)(_CartegoryCard));