import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerStrings, MyCustomTabs, headerActions, breadCrumbActions, mainStageHeaderStrings, mainStageHeaderAction } from '../../../includes';
import { StaffCategories } from './StaffCategories';
import { Forms } from './Forms';
import { routeNamesSchool } from '../../routeNames';

const style = theme => ({
    root: {
    }
})
class _StaffSetup extends Component {
    constructor(props) {
        super(props);
        this.state = {
            tabValue : null
        }
        headerActions({
            [headerStrings.headerTitle] : "STAFF SETTINGS"
        })(props.dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", path : routeNamesSchool.dashboard},
            {name : "Staff Setup", path : routeNamesSchool.staffSetup}
        ])(props.dispatch);
        mainStageHeaderAction({
            [mainStageHeaderStrings.buttons] : null,
            [mainStageHeaderStrings.searchActions] : null,
        })(props.dispatch);
    }
    
    tabs = {form : "Forms", cat : "Categories", }
    getTabContext = context => this.tabContext = context;
    render() {
        const {classes} = this.props;
        const {tabValue} = this.state;
        return (
            <div className={classes.root}>
                <MyCustomTabs
                    position="sticky"
                    tabs={this.tabs}
                    getInitialTabValue={tabValue=>this.setState({tabValue})}/>
                
                <div style={{padding: 5, marginTop : 20}}>
                    {tabValue === "cat" && <StaffCategories/>}
                    {tabValue === "form" && <Forms/>}
                </div>
            </div>
        );
    }
}


_StaffSetup.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = state => ({
    state
})


export const StaffSetup = connect(mapStateToProps)(withStyles(style)(_StaffSetup));
export {StaffSetup as default};