import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { staffStrings } from '../../config';
import { staffActions } from '../../actions';
import { CategoryCard } from './CategoryCard';
import FormInputList from './FormInputList';
import { values, customSuperSetState } from '../../../../../utils';
import { Grid } from '@material-ui/core';


const style = theme => ({
    root: {
    },
    listContainer :{
        marginTop : 30
    }
})
class _Forms extends Component {
    constructor(props) {
        super(props);
        this.state={
            selectedCat : {},
            selectedList : []
        }
    }
    
    componentDidMount(){
        if(!this.props[staffStrings.categories]){
            staffActions.getStaffCategories()(this.props.dispatch);
        }
        if(!this.props[staffStrings.formAdmin]){
            staffActions.getStaffForms.admin()(this.props.dispatch);
        }
        if(!this.props[staffStrings.formTeacher]){
            staffActions.getStaffForms.teacher()(this.props.dispatch);
        }
        if(!this.props[staffStrings.formOthers]){
            staffActions.getStaffForms.others()(this.props.dispatch);
        }    
    }
    setSeleetedCat = selectedCat=>()=>this.setState({
        selectedCat, selectedList : this.selectCategoryList(selectedCat)
    })
    setMyState = customSuperSetState(this);
    selectCategoryList(categories){
        const {
            [staffStrings.formAdmin] : adminForm = [],
            [staffStrings.formTeacher] : teacherForm = [],
            [staffStrings.formOthers] : otherForm = [],
        } = this.props;
        switch(categories.value){
            case values.admin :  return adminForm;
            // case values.other : return otherForm;
            case values.teacher : return teacherForm;
            default : return otherForm;
        }
    }
    newFieldFormat = {new : true, edit : true, name : "", placeholder : "", label : "", required : "", inputType : ""}
    render() {
        let { selectedCat, selectedList} = this.state;
        const {
            classes,
            [staffStrings.categories] : categories = []
        } = this.props;
        if(selectedList.length != 0 && 
        !selectedList[selectedList.length -1].new) 
            selectedList = [...selectedList, this.newFieldFormat];
        return (
            <div style={{margin : 10, position : "relative"}}>
                <Grid container spacing={2} className={classes.root}>
                    <Grid style={{padding : 5}} item xs={12} sm={6} md={3} lg={3} xl={3}>
                        <CategoryCard categories={categories} setSeleetedCat={this.setSeleetedCat.bind(this)}/>
                    </Grid>
                    <Grid style={{padding : 0}} item xs={12} sm={12} md={9} lg={9} xl={9}>
                        <FormInputList 
                            classes={{root : classes.listContainer}} i
                            inputList={selectedList}
                            selectedCat={selectedCat}
                            superSetState={this.setMyState.bind(this)}/>
                    </Grid>
                </Grid>
            </div>
        );
    }
}


_Forms.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({staffReducer}) => ({
    ...staffReducer
})


export const Forms = connect(mapStateToProps)(withStyles(style)(_Forms));