import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Card, TableCell, CardHeader, CardContent, IconButton, TextField } from '@material-ui/core';
import { MyTable, InfoText } from "../../../../includes";
import { Edit, Done, Add } from '@material-ui/icons';
import { values, colors } from '../../../../../utils';
import { staffStrings } from '../../config';


const style = theme => ({
    root: {
        padding : 0
    },
    tableCell : {
        padding : 5
    }
})
class SmartTextField extends Component {
    constructor(props) {
        super(props);
        this.state = {
            value : ""
        }
        if(props.getContext) 
            props.getContext(this);
    }
    static getDerivedStateFromProps(nextProps, prevState) {
        if(nextProps.name && !prevState.value){
            prevState.value = nextProps.value;
        }
        return prevState;
    }
    handleChange = name => e => this.setState({[name]: e.target.value});
    render(){
        const {value} = this.state;
        return (
            <TextField
                style={{width : "100%"}}
                value={value}
                margin="normal"
                onChange={this.handleChange("value")}/>
        )
    }
}
class _FormInputList extends Component {
    
    cellMap = (editClick, doneClick) => ({row, cellMap}) => {
        const {classes} = this.props;
        if(row.edit){ 
            switch(cellMap){
                case "action" : return <TableCell>
                    <IconButton onClick={doneClick(row)}>
                        {row.new ? 
                            <Add style={{color : colors.secondary}}/> : <Done style={{color : colors.secondary}}/>}
                    </IconButton>
                </TableCell>
                default : return <TableCell className={classes.tableCell}>
                    <SmartTextField name={cellMap} value={row[cellMap]}/>
                </TableCell>
            }
        }else {
            switch(cellMap){
                case "required" : return <TableCell className={classes.tableCell}>{
                    row[cellMap] ? (row[cellMap] === 1 ? "Yes" : "No") : "No"
                }</TableCell> ;
                case "inputType" : return <TableCell className={classes.tableCell}>{
                    row[cellMap] ? row[cellMap] : "text"
                }</TableCell>;
                case "action" : return <TableCell className={classes.tableCell}>
                    <IconButton onClick={editClick(row)}><Edit/></IconButton>
                </TableCell>
                default : return <TableCell className={classes.tableCell}>{row[cellMap]}</TableCell>
            }
        }
    }
    completEditButtonHandler = row => ()=> {
        const {inputList, selectedCat} = this.props;
        for (let i = 0; i < inputList.length; i++) {
            const element = inputList[i];
            if(element.name === row.name){
                delete inputList[i].edit;
            }
        }
        this.props.superSetState({selectedList : inputList});
        /** super holds the state */
        // staffActions.setStaffForm({
        //     [this.getFormTypeName(selectedCat.value)] : inputList
        // })(this.props.dispatch);
    }
    editButtonHandler = row => () => {
        const {selectedCat} = this.props;
        let inputList = [...this.props.inputList]
        for (let i = 0; i < inputList.length; i++) {
            const element = inputList[i];
            if(element.name === row.name){
                inputList[i] = {...inputList[i], edit : true};
            }
        }
        this.props.superSetState({selectedList : inputList});
        /** super holds the state */
        // staffActions.setStaffForm({
        //     [this.getFormTypeName(selectedCat.value)] : inputList
        // })(this.props.dispatch);
    }
    getFormTypeName = catName => { 
        let formType;
        switch(catName){
            case values.admin : formType = staffStrings.formAdmin; break;
            case values.teacher : formType = staffStrings.formTeacher; break;
            case values.other : formType = staffStrings.formOthers; break;
        }
        return formType;
    }
    render() {
        const {classes, inputList = [], category, selectedCat} = this.props;
        return (
            <Card elevation={0} className={classes.root}>
                <CardHeader title={selectedCat && "Input fields for " +selectedCat.name}/>
                <CardContent>
                    {!selectedCat.name && <InfoText>Select a category to show input list</InfoText>}
                    <MyTable 
                        header={["Name", "Label", "Placeholder", "Required", "Input type", ""]}
                        dataMap={["name", "label", "placeholder", "required", "inputType", "action"]}
                        data={inputList}
                        CellMap={this.cellMap(this.editButtonHandler, this.completEditButtonHandler)}/>    
                </CardContent>

            </Card>
        );
    }
}


_FormInputList.propTypes = {
    classes : PropTypes.object.isRequired,
    inputList : PropTypes.array,
    selectedCat : PropTypes.object,
    superSetState : PropTypes.func,
};

export const FormInputList = connect()(withStyles(style)(_FormInputList));
export {FormInputList as default};