import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import { withStyles, Card, CardHeader, CardContent, List, ListItem, ListItemText } from '@material-ui/core';
import { staffStrings } from '../../config';
import {connect} from 'react-redux';
const styles = theme => ({
    root : {

    }
})
class _CategoryCard extends PureComponent {
    
    render() {
        const {classes} = this.props;
        const {setSeleetedCat, categories} = this.props;
        return (
            <Card>
                <CardHeader 
                    title="Staff Categories"
                    subheader="The different types of staff"/>
                    <CardContent>
                        <List>
                        {categories && categories.map((cat, index) => 
                            <ListItem  onClick={setSeleetedCat && setSeleetedCat(cat)} style={{padding : 0}} divider key={index} button>
                                <ListItemText>
                                    {cat.name}
                                </ListItemText>
                            </ListItem>)}
                        </List>
                </CardContent>
            </Card>
        );
    }
}

_CategoryCard.propTypes = {
    categories : PropTypes.array,
    setSeleetedCat : PropTypes.func,
};
const mapStateToProps = ({staffReducer}) => ({
    [staffStrings.categories] : staffReducer[staffStrings.categories]
})
export const CategoryCard = connect(mapStateToProps)(withStyles(styles)(_CategoryCard));